async (params, browser) => {
  // Open Notion
  await browser.open('https://www.notion.so')

  // Let Notion load
  await browser.wait(3000)

  // Create page via Notion API
  const result = await browser.evaluate(`const parentUrl = params.parent_page_url; let spaceId = ''; const spaceResp = await fetch('/api/v3/getSpaces', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: '{}' }); if (spaceResp.ok) { const spaces = await spaceResp.json(); const firstUser = Object.keys(spaces)[0]; if (firstUser) { const userSpaces = spaces[firstUser]?.space; spaceId = userSpaces ? Object.keys(userSpaces)[0] : ''; } } const pageId = crypto.randomUUID(); const now = Date.now(); const ops = [{ id: pageId, table: 'block', path: [], command: 'set', args: { type: 'page', id: pageId, version: 1, alive: true, created_time: now, last_edited_time: now, space_id: spaceId, properties: { title: [[ params.title ]] } } }]; const contentText = params.content; if (contentText) { const blockId = crypto.randomUUID(); ops.push({ id: blockId, table: 'block', path: [], command: 'set', args: { type: 'text', id: blockId, version: 1, alive: true, parent_id: pageId, parent_table: 'block', created_time: now, last_edited_time: now, space_id: spaceId, properties: { title: [[ contentText ]] } } }); ops.push({ id: pageId, table: 'block', path: ['content'], command: 'listAfter', args: { id: blockId } }); } const resp = await fetch('/api/v3/submitTransaction', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify({ operations: ops }) }); if (!resp.ok) throw new Error('Create page failed: ' + resp.status); return { success: true, page_id: pageId, title: params.title, url: 'https://www.notion.so/' + pageId.replace(/-/g, '') }`)

  return result
}
